// Normalize HN Algolia search results into Signal Log row format.
// Algolia returns { hits: [ {title, url, author, story_text, created_at, objectID, ...} ] }
// We filter to ICP-relevant posts, extract a best-effort company domain, and emit one row per hit.

const payload = $input.first().json;
const hits = Array.isArray(payload.hits) ? payload.hits : [];
const today = new Date().toISOString().split('T')[0];

// ICP keyword whitelist — second-pass filter (Algolia query is broad; this tightens it)
const keywords = [
  'gainsight', 'churnzero', 'totango', 'planhat',
  'renewal', 'revops', 'revenue operations',
  'customer success operations', 'cs ops', 'cs-ops',
  'nrr', 'gross retention', 'net retention',
  'churn prediction', 'churn intelligence',
  'expansion revenue', 'product telemetry'
];

// Domain extraction: parse hostname from URL field.
// Many HN posts link to a company blog or product page, which is the strongest domain signal.
// If no URL (Ask HN, Show HN with no link), domain is left blank — WF3 will skip rows with empty domain,
// and the row remains in Signal Log as triage material for manual review.
function extractDomain(url) {
  if (!url) return '';
  try {
    return String(url)
      .trim()
      .toLowerCase()
      .replace(/^https?:\/\//, '')
      .replace(/^www\./, '')
      .split('/')[0]
      .split('?')[0]
      .split('#')[0];
  } catch {
    return '';
  }
}

// Best-effort company name from the domain (everything before the first dot, title-cased)
function inferCompanyName(domain) {
  if (!domain) return '';
  const root = domain.split('.')[0];
  return root.charAt(0).toUpperCase() + root.slice(1);
}

return hits
  .filter(hit => {
    const text = ((hit.title || '') + ' ' + (hit.story_text || '')).toLowerCase();
    return keywords.some(kw => text.includes(kw));
  })
  .map(hit => {
    const sourceUrl = hit.url || ('https://news.ycombinator.com/item?id=' + hit.objectID);
    const domain = extractDomain(hit.url);
    return {
      json: {
        'Date': today,
        'Company Domain': domain,
        'Company Name': inferCompanyName(domain),
        'Signal Type': '1',
        'Signal Summary': '[HN Discussion] ' + (hit.title || '').slice(0, 200),
        'Source URL': sourceUrl,
        'Status': 'New'
      }
    };
  })
  .filter(item => item.json['Company Domain']);
